/* a+ core 2 :: content/questions3.js — Domain 3 Software Troubleshooting (220-1202). */
window.APLUS2 = window.APLUS2 || {};
APLUS2.questions = APLUS2.questions || [];
APLUS2.questions.push(
{ id:"D3-001", domain:3, obj:"3.1", diff:"medium", q:"A Windows 11 workstation displays a blue screen with the stop code MEMORY_MANAGEMENT and reboots before the desktop loads. The crashes began immediately after a user added a new RAM module. What is the BEST first step to confirm the cause?", options:["Run the Windows Memory Diagnostic tool","Reinstall Windows from recovery media","Replace the motherboard","Disable the page file in System Properties"], answer:0, explain:"<strong>Run the Windows Memory Diagnostic tool</strong> is correct because a MEMORY_MANAGEMENT stop code appearing right after adding RAM points to faulty or incompatible memory, and the diagnostic tests modules without altering the system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall Windows from recovery media</b>: This is drastic and does not address a hardware fault.</span><span class='qd'><b>Replace the motherboard</b>: Premature; nothing indicates the board is bad.</span><span class='qd'><b>Disable the page file in System Properties</b>: This can worsen low-memory issues and does not test the new RAM.</span>" },
{ id:"D3-002", domain:3, obj:"3.1", diff:"hard", q:"A PC powers on, shows the manufacturer logo, then displays \"No operating system found.\" The drive spins and was working yesterday. Which tool is MOST likely to repair the issue without reinstalling Windows?", options:["sfc /scannow from the desktop","bootrec /fixboot and /rebuildbcd from the recovery environment","chkdsk /r from Safe Mode","Defragment the system drive"], answer:1, explain:"<strong>bootrec /fixboot and /rebuildbcd from the recovery environment</strong> is correct because a missing OS message usually means a corrupt boot sector or boot configuration data, which bootrec rebuilds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sfc /scannow from the desktop</b>: You cannot reach the desktop, and SFC repairs system files, not the boot record.</span><span class='qd'><b>chkdsk /r from Safe Mode</b>: Safe Mode also requires a bootable OS, which is unavailable.</span><span class='qd'><b>Defragment the system drive</b>: Defragmentation does not restore boot data.</span>" },
{ id:"D3-003", domain:3, obj:"3.1", diff:"medium", q:"A user reports that Windows takes several minutes to reach the desktop and applications open slowly. Task Manager shows disk usage pegged at 100% with the System process highest. Which action is the BEST first troubleshooting step?", options:["Add more RAM","Replace the CPU","Check the Startup tab and disable unnecessary startup apps","Increase the monitor refresh rate"], answer:2, explain:"<strong>Check the Startup tab and disable unnecessary startup apps</strong> is correct because excessive startup programs are a common cause of slow boots and high disk activity, and disabling them is a quick, reversible step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more RAM</b>: Memory was not identified as the bottleneck; disk is at 100%.</span><span class='qd'><b>Replace the CPU</b>: CPU was not the limiting resource and replacement is costly.</span><span class='qd'><b>Increase the monitor refresh rate</b>: Unrelated to load times.</span>" },
{ id:"D3-004", domain:3, obj:"3.1", diff:"easy", q:"Which built-in Windows utility lets a technician selectively disable startup services and choose a diagnostic or selective startup to isolate boot problems?", options:["Disk Management","Resource Monitor","Device Manager","msconfig (System Configuration)"], answer:3, explain:"<strong>msconfig (System Configuration)</strong> is correct because it provides Boot, Services, and Startup options used to perform a clean or selective startup for troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Management</b>: Manages partitions and volumes, not startup items.</span><span class='qd'><b>Resource Monitor</b>: Shows live resource usage but cannot change startup configuration.</span><span class='qd'><b>Device Manager</b>: Manages hardware and drivers, not boot configuration.</span>" },
{ id:"D3-005", domain:3, obj:"3.1", diff:"hard", q:"After a recent Windows feature update, a laptop bluescreens with DRIVER_IRQL_NOT_LESS_OR_EQUAL referencing the network adapter driver. The system boots normally into Safe Mode. What is the MOST appropriate fix?", options:["Roll back the network adapter driver in Device Manager","Run chkdsk /f on the system volume","Reset the BIOS to defaults","Disable the page file"], answer:0, explain:"<strong>Roll back the network adapter driver in Device Manager</strong> is correct because the stop code names the network driver and the problem started after an update, so reverting to the previous working driver is the targeted fix.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run chkdsk /f on the system volume</b>: This checks the file system, not driver faults.</span><span class='qd'><b>Reset the BIOS to defaults</b>: Firmware settings are unrelated to the named driver.</span><span class='qd'><b>Disable the page file</b>: Does not address a driver-level IRQL fault.</span>" },
{ id:"D3-006", domain:3, obj:"3.1", diff:"medium", q:"A technician suspects corrupt Windows system files are causing intermittent application crashes. Which command should be run FIRST to scan and repair protected system files?", options:["diskpart","sfc /scannow","format C:","ipconfig /flushdns"], answer:1, explain:"<strong>sfc /scannow</strong> is correct because System File Checker scans integrity of protected system files and replaces corrupted versions from a cached copy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>diskpart</b>: Manages partitions and can be destructive; it does not repair files.</span><span class='qd'><b>format C:</b>: Erases the drive entirely.</span><span class='qd'><b>ipconfig /flushdns</b>: Clears the DNS resolver cache, unrelated to system files.</span>" },
{ id:"D3-007", domain:3, obj:"3.1", diff:"hard", q:"sfc /scannow reports it found corrupt files but could not repair some of them. Which command should the technician run NEXT to repair the underlying component store so SFC can succeed?", options:["bootrec /fixmbr","chkdsk /r","DISM /Online /Cleanup-Image /RestoreHealth","gpupdate /force"], answer:2, explain:"<strong>DISM /Online /Cleanup-Image /RestoreHealth</strong> is correct because it repairs the Windows component store (the source SFC uses), and is the standard next step when SFC cannot fix files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>bootrec /fixmbr</b>: Repairs the master boot record, not the component store.</span><span class='qd'><b>chkdsk /r</b>: Checks disk integrity and bad sectors, not Windows image health.</span><span class='qd'><b>gpupdate /force</b>: Refreshes Group Policy, unrelated to file repair.</span>" },
{ id:"D3-008", domain:3, obj:"3.1", diff:"medium", q:"A user's profile loads with a temporary desktop and none of their personal settings or files appear. The event log shows the user profile service could not load the profile. What is the recommended remediation?", options:["Reinstall the application that opened last","Replace the hard drive","Update the BIOS","Rebuild or recreate the corrupt user profile"], answer:3, explain:"<strong>Rebuild or recreate the corrupt user profile</strong> is correct because a temporary profile loading instead of the real one is the classic symptom of a corrupt user profile, fixed by rebuilding it and migrating data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the application that opened last</b>: The issue is profile-wide, not app-specific.</span><span class='qd'><b>Replace the hard drive</b>: No disk failure is indicated.</span><span class='qd'><b>Update the BIOS</b>: Firmware has nothing to do with a Windows profile fault.</span>" },
{ id:"D3-009", domain:3, obj:"3.1", diff:"easy", q:"Which Windows boot option starts the OS with a minimal set of drivers and services, useful for removing malware or troubleshooting a driver that prevents normal boot?", options:["Safe Mode","Hibernate","Fast Startup","Sleep"], answer:0, explain:"<strong>Safe Mode</strong> is correct because it loads only essential drivers and services, isolating third-party software and drivers during troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hibernate</b>: A power state that saves memory to disk; not a diagnostic mode.</span><span class='qd'><b>Fast Startup</b>: A hybrid shutdown feature, not a minimal boot.</span><span class='qd'><b>Sleep</b>: A low-power standby state, not a troubleshooting mode.</span>" },
{ id:"D3-010", domain:3, obj:"3.1", diff:"hard", q:"A desktop randomly shuts down without warning under load, with no blue screen and no event log error. The CPU temperature readings spike just before each shutdown. Which is the MOST likely cause?", options:["Corrupt user profile","Thermal protection triggered by overheating","Missing Windows updates","Fragmented hard drive"], answer:1, explain:"<strong>Thermal protection triggered by overheating</strong> is correct because abrupt, error-free shutdowns correlated with high CPU temperatures indicate the system is protecting hardware by powering off.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Corrupt user profile</b>: Profile faults do not cause power-off events tied to temperature.</span><span class='qd'><b>Missing Windows updates</b>: Updates do not produce thermal shutdowns.</span><span class='qd'><b>Fragmented hard drive</b>: Fragmentation slows access but does not power down the system.</span>" },
{ id:"D3-011", domain:3, obj:"3.1", diff:"medium", q:"A Windows service set to Automatic fails to start at boot, and dependent applications error out. Where should a technician look FIRST to determine why the service failed?", options:["Performance Monitor counters","Disk Defragmenter report","Event Viewer System and Application logs","Resource Monitor network tab"], answer:2, explain:"<strong>Event Viewer System and Application logs</strong> is correct because service start failures and their error codes or dependency issues are recorded there, guiding the next step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performance Monitor counters</b>: Tracks metrics over time, not discrete failure events.</span><span class='qd'><b>Disk Defragmenter report</b>: Reports fragmentation, unrelated to services.</span><span class='qd'><b>Resource Monitor network tab</b>: Shows live network usage, not service errors.</span>" },
{ id:"D3-012", domain:3, obj:"3.1", diff:"medium", q:"A user receives \"Your computer is low on memory\" warnings and apps close unexpectedly even though Task Manager shows free physical RAM. Which configuration is the MOST likely culprit?", options:["The screen resolution is too high","The keyboard layout is incorrect","The antivirus definitions are outdated","The page file (virtual memory) is set too small or disabled"], answer:3, explain:"<strong>The page file (virtual memory) is set too small or disabled</strong> is correct because low-memory warnings with free physical RAM often indicate insufficient virtual memory to back commit charge.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The screen resolution is too high</b>: Affects display, not memory commit.</span><span class='qd'><b>The keyboard layout is incorrect</b>: Cosmetic input setting, unrelated.</span><span class='qd'><b>The antivirus definitions are outdated</b>: A security concern, not a memory allocation cause.</span>" },
{ id:"D3-013", domain:3, obj:"3.1", diff:"hard", q:"Windows fails to boot after a power outage, showing \"INACCESSIBLE_BOOT_DEVICE.\" The drive is detected in BIOS. The technician boots to WinRE. Which command BEST checks and repairs file system errors on the system volume?", options:["chkdsk C: /f /r","sfc /verifyonly","wmic diskdrive get status","cipher /w:C"], answer:0, explain:"<strong>chkdsk C: /f /r</strong> is correct because file-system corruption from an unexpected power loss commonly causes this stop code, and chkdsk fixes errors and recovers readable data from bad sectors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sfc /verifyonly</b>: Only checks system files and does not write repairs.</span><span class='qd'><b>wmic diskdrive get status</b>: Reports SMART status only.</span><span class='qd'><b>cipher /w:C</b>: Wipes free space, which is destructive and irrelevant here.</span>" },
{ id:"D3-014", domain:3, obj:"3.1", diff:"medium", q:"Several recently installed Windows updates appear to have caused instability and login failures across multiple machines. What is the BEST corrective action?", options:["Disable the Windows Update service permanently","Roll back the problematic updates and pause further updates pending testing","Reimage every affected machine immediately","Delete the user profiles"], answer:1, explain:"<strong>Roll back the problematic updates and pause further updates pending testing</strong> is correct because uninstalling the offending updates restores stability while pausing prevents re-deployment until validated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disable the Windows Update service permanently</b>: Leaves systems unpatched and insecure.</span><span class='qd'><b>Reimage every affected machine immediately</b>: Excessive when a targeted rollback resolves it.</span><span class='qd'><b>Delete the user profiles</b>: Does not address an update-caused fault.</span>" },
{ id:"D3-015", domain:3, obj:"3.1", diff:"hard", q:"A workstation shows repeated USB controller resource warnings in Device Manager, and devices on certain ports stop responding. Which step is MOST appropriate to resolve resource contention?", options:["Replace the power supply","Reinstall the operating system","Move high-bandwidth devices to a powered hub or different controller and update chipset/USB drivers","Increase the page file size"], answer:2, explain:"<strong>Move high-bandwidth devices to a powered hub or different controller and update chipset/USB drivers</strong> is correct because USB controller resource warnings indicate bandwidth or power contention, relieved by redistributing devices and updating drivers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the power supply</b>: Unnecessary unless system power is failing, which is not indicated.</span><span class='qd'><b>Reinstall the operating system</b>: Disproportionate to a controller bandwidth issue.</span><span class='qd'><b>Increase the page file size</b>: Memory paging is unrelated to USB controllers.</span>" },
{ id:"D3-016", domain:3, obj:"3.1", diff:"medium", q:"A single application crashes on launch with the same error each time, but the rest of Windows is stable. Which is the BEST first action?", options:["Reinstall Windows","Replace the system board","Run a full memory test","Reinstall or repair just that application"], answer:3, explain:"<strong>Reinstall or repair just that application</strong> is correct because an isolated app crash with a stable OS points to corrupt application files, repaired by reinstalling or running the app's repair option.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall Windows</b>: Excessive when only one app is affected.</span><span class='qd'><b>Replace the system board</b>: No hardware fault is indicated.</span><span class='qd'><b>Run a full memory test</b>: RAM faults would affect more than one app.</span>" },
{ id:"D3-017", domain:3, obj:"3.1", diff:"easy", q:"Which feature lets a technician return Windows system files and settings to an earlier working state without affecting personal documents?", options:["System Restore (restore point)","Disk Cleanup","Storage Sense","File History"], answer:0, explain:"<strong>System Restore (restore point)</strong> is correct because it reverts system files, registry, and drivers to a saved point while leaving personal files intact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Cleanup</b>: Frees space by deleting temporary files.</span><span class='qd'><b>Storage Sense</b>: Automates freeing disk space.</span><span class='qd'><b>File History</b>: Backs up and restores personal files, not system state.</span>" },
{ id:"D3-018", domain:3, obj:"3.1", diff:"hard", q:"A laptop boots to a black screen with a movable cursor after a graphics driver update; Safe Mode works. The technician wants the least invasive fix. What should be done?", options:["Reimage the laptop","Boot to Safe Mode and roll back the display driver","Replace the display panel","Run sfc /scannow only"], answer:1, explain:"<strong>Boot to Safe Mode and roll back the display driver</strong> is correct because a black screen after a driver update that resolves in Safe Mode indicates a bad display driver, reversed by rolling it back.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reimage the laptop</b>: Far too invasive for a driver issue.</span><span class='qd'><b>Replace the display panel</b>: The panel works in Safe Mode, so it is not faulty.</span><span class='qd'><b>Run sfc /scannow only</b>: SFC does not revert a third-party display driver.</span>" },
{ id:"D3-019", domain:3, obj:"3.1", diff:"medium", q:"A technician determines that the only practical way to recover a machine with widespread corruption and an unknown configuration drift is to deploy a known-good standard image. This process is BEST described as:", options:["Performing a system restore","Running chkdsk","Reimaging the device","Rebuilding the profile"], answer:2, explain:"<strong>Reimaging the device</strong> is correct because applying a known-good standard image replaces the entire OS and configuration, which is appropriate for widespread, unidentifiable corruption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performing a system restore</b>: Only reverts to a prior point, which may also be corrupt.</span><span class='qd'><b>Running chkdsk</b>: Fixes file-system errors, not full configuration drift.</span><span class='qd'><b>Rebuilding the profile</b>: Addresses one user's profile, not system-wide corruption.</span>" },
{ id:"D3-020", domain:3, obj:"3.1", diff:"medium", q:"A user complains Windows is sluggish; investigation shows the system drive is 99% full and the page file cannot expand. Which action MOST directly addresses the slowdown?", options:["Disable Windows Defender","Lower the screen resolution","Disable the firewall","Free disk space with Disk Cleanup and move or remove large files"], answer:3, explain:"<strong>Free disk space with Disk Cleanup and move or remove large files</strong> is correct because a nearly full system drive starves the page file and temp operations, so reclaiming space restores performance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disable Windows Defender</b>: Reduces security and does not address full disk.</span><span class='qd'><b>Lower the screen resolution</b>: Does not free storage.</span><span class='qd'><b>Disable the firewall</b>: Unrelated security change that does not free space.</span>" },
{ id:"D3-021", domain:3, obj:"3.1", diff:"hard", q:"After installing a third-party kernel-mode driver, a server bluescreens during every boot and Safe Mode also fails. Which recovery option lets the technician disable the offending driver to regain a normal boot?", options:["WinRE Command Prompt with bcdedit/dism or the Startup Settings menu to disable driver signature enforcement and boot to remove the driver","Startup Repair only","Reset the BIOS clock","Run Storage Sense"], answer:0, explain:"<strong>WinRE Command Prompt with bcdedit/dism or the Startup Settings menu to disable driver signature enforcement and boot to remove the driver</strong> is correct because when even Safe Mode fails, the recovery environment lets you disable or remove the bad driver to restore booting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Startup Repair only</b>: It may not remove a specific third-party driver causing the crash.</span><span class='qd'><b>Reset the BIOS clock</b>: Time settings do not affect driver-induced bluescreens.</span><span class='qd'><b>Run Storage Sense</b>: A cleanup tool unrelated to driver removal.</span>" },
{ id:"D3-022", domain:3, obj:"3.1", diff:"easy", q:"Which command-line tool checks a disk for errors and bad sectors and can mark and recover data from bad sectors with the /r switch?", options:["ping","chkdsk","tracert","robocopy"], answer:1, explain:"<strong>chkdsk</strong> is correct because it scans the file system for errors and, with /r, locates bad sectors and recovers readable information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping</b>: Tests network reachability.</span><span class='qd'><b>tracert</b>: Traces the network path to a host.</span><span class='qd'><b>robocopy</b>: Copies files and directories.</span>" },
{ id:"D3-023", domain:3, obj:"3.4", diff:"medium", q:"A user's smartphone app freezes every time it opens a large photo gallery, while other apps are fine. After force-closing, it freezes again. What is the BEST next step?", options:["Replace the phone's battery","Disable the cellular radio","Clear the app's cache and data, then update or reinstall it","Reset all network settings"], answer:2, explain:"<strong>Clear the app's cache and data, then update or reinstall it</strong> is correct because a single app repeatedly freezing is commonly caused by corrupt cached data, fixed by clearing it and updating/reinstalling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the phone's battery</b>: Battery health does not cause one app to freeze.</span><span class='qd'><b>Disable the cellular radio</b>: Connectivity is not the issue for a frozen gallery.</span><span class='qd'><b>Reset all network settings</b>: Network resets do not fix corrupt app data.</span>" },
{ id:"D3-024", domain:3, obj:"3.4", diff:"hard", q:"A user reports that several apps on their phone close unexpectedly and the device feels slow, especially after installing many new apps. Storage is nearly full and RAM is frequently maxed. Which is the BEST remedy?", options:["Replace the SIM card","Disable auto-rotate","Lower the ringtone volume","Uninstall unused apps and clear caches to free storage and memory, then reboot"], answer:3, explain:"<strong>Uninstall unused apps and clear caches to free storage and memory, then reboot</strong> is correct because low free storage and exhausted RAM cause app crashes and sluggishness, relieved by reclaiming space and memory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the SIM card</b>: The SIM does not affect memory or storage.</span><span class='qd'><b>Disable auto-rotate</b>: A display setting unrelated to crashes.</span><span class='qd'><b>Lower the ringtone volume</b>: Has no effect on performance.</span>" },
{ id:"D3-025", domain:3, obj:"3.4", diff:"medium", q:"A user says their phone will not update a particular app; the update starts but always fails near the end. Free storage shows only a few hundred megabytes. What is the MOST likely cause?", options:["Insufficient free storage to complete the update","The screen digitizer is failing","The proximity sensor is dirty","The vibration motor is broken"], answer:0, explain:"<strong>Insufficient free storage to complete the update</strong> is correct because app updates need temporary space, and a nearly full device commonly fails updates until space is freed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The screen digitizer is failing</b>: Touch hardware does not affect updates.</span><span class='qd'><b>The proximity sensor is dirty</b>: Sensors are unrelated to app updates.</span><span class='qd'><b>The vibration motor is broken</b>: Has no bearing on updating apps.</span>" },
{ id:"D3-026", domain:3, obj:"3.4", diff:"medium", q:"A user complains their phone's display is too dim indoors even at full manual brightness, and it recently got worse. Auto-brightness is off. What should the technician investigate?", options:["The cellular APN settings","A battery-saver/power-saving mode that caps brightness, or a failing backlight/panel","The default search engine","The Bluetooth codec"], answer:1, explain:"<strong>A battery-saver/power-saving mode that caps brightness, or a failing backlight/panel</strong> is correct because power-saving modes limit maximum brightness, and if disabling them does not help, a failing backlight or panel is implicated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cellular APN settings</b>: APN controls data, not brightness.</span><span class='qd'><b>The default search engine</b>: A browser setting unrelated to the display.</span><span class='qd'><b>The Bluetooth codec</b>: Audio configuration, not brightness.</span>" },
{ id:"D3-027", domain:3, obj:"3.4", diff:"hard", q:"A user's phone overheats and shuts down only while running a graphics-intensive game in a thick protective case. Battery health is good and the OS is current. What is the BEST advice?", options:["Replace the logic board","Disable the GPS","Remove the case during heavy gaming, lower in-game graphics settings, and avoid charging while playing","Reinstall the email app"], answer:2, explain:"<strong>Remove the case during heavy gaming, lower in-game graphics settings, and avoid charging while playing</strong> is correct because a thick case plus heavy GPU load traps heat and triggers thermal shutdown, eased by improving cooling and reducing load.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the logic board</b>: No board fault is indicated.</span><span class='qd'><b>Disable the GPS</b>: GPS is not what overheats during gaming.</span><span class='qd'><b>Reinstall the email app</b>: Unrelated to gaming heat.</span>" },
{ id:"D3-028", domain:3, obj:"3.4", diff:"medium", q:"A user's phone shows no sound from notifications or media, but a headphone icon appears in the status bar even though nothing is plugged in. What is the MOST likely cause?", options:["The cellular signal is weak","The storage is full","The fingerprint reader failed","The OS thinks headphones are connected due to debris or a stuck/faulty headphone jack"], answer:3, explain:"<strong>The OS thinks headphones are connected due to debris or a stuck/faulty headphone jack</strong> is correct because a persistent headphone icon routes audio away from the speaker, often from lint or a faulty jack switch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cellular signal is weak</b>: Signal does not mute speaker audio.</span><span class='qd'><b>The storage is full</b>: Full storage does not reroute audio.</span><span class='qd'><b>The fingerprint reader failed</b>: Biometrics are unrelated to sound output.</span>" },
{ id:"D3-029", domain:3, obj:"3.4", diff:"hard", q:"A user reports their phone cannot connect to any Wi-Fi or Bluetooth device, and even cellular shows no service after a failed OS update. A reboot did not help. What is a reasonable next step before a factory reset?", options:["Toggle airplane mode off/on, then reset network settings; if it persists, reinstall the OS update","Replace the screen","Clear the photo gallery","Disable notifications"], answer:0, explain:"<strong>Toggle airplane mode off/on, then reset network settings; if it persists, reinstall the OS update</strong> is correct because a failed update can corrupt radio/network configuration, often fixed by resetting network settings or reapplying the update before a full reset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the screen</b>: The display is unrelated to radios.</span><span class='qd'><b>Clear the photo gallery</b>: Freeing photos does not restore connectivity.</span><span class='qd'><b>Disable notifications</b>: Has no effect on Wi-Fi, Bluetooth, or cellular.</span>" },
{ id:"D3-030", domain:3, obj:"3.4", diff:"easy", q:"Which mobile symptom is the clearest sign of a single misbehaving app rather than a device-wide hardware fault?", options:["The screen is physically cracked","Only one app crashes repeatedly while everything else works","The phone will not charge on any cable","The earpiece produces no sound on any call"], answer:1, explain:"<strong>Only one app crashes repeatedly while everything else works</strong> is correct because an isolated app crashing points to an app-level problem, not hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The screen is physically cracked</b>: A hardware defect.</span><span class='qd'><b>The phone will not charge on any cable</b>: A charging/hardware issue.</span><span class='qd'><b>The earpiece produces no sound on any call</b>: A hardware or system-wide audio fault.</span>" },
{ id:"D3-031", domain:3, obj:"3.5", diff:"medium", q:"A user receives a notification that they have exceeded their monthly data limit, but they rarely stream and their usage was normal last month. What should the technician suspect FIRST?", options:["A defective charger","A dim display","A background app or malware consuming data and possibly exfiltrating it","A worn power button"], answer:2, explain:"<strong>A background app or malware consuming data and possibly exfiltrating it</strong> is correct because an unexplained data-limit overage with unchanged habits suggests a rogue app or malware transmitting data in the background.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A defective charger</b>: Charging hardware does not consume data.</span><span class='qd'><b>A dim display</b>: A display setting unrelated to data usage.</span><span class='qd'><b>A worn power button</b>: A hardware control, not a data consumer.</span>" },
{ id:"D3-032", domain:3, obj:"3.5", diff:"hard", q:"A security team finds a corporate phone is sending large volumes of data to an unknown server during off-hours, and the user reports sluggish performance and rapid battery drain. Which conclusion is BEST supported?", options:["The phone simply needs a software update","The screen brightness is too high","The ringtone volume is too low","Malware is likely active, causing high network traffic, resource use, and possible data leakage"], answer:3, explain:"<strong>Malware is likely active, causing high network traffic, resource use, and possible data leakage</strong> is correct because off-hours data transfers to unknown servers combined with drain and sluggishness strongly indicate malware exfiltrating data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The phone simply needs a software update</b>: Updates do not send data to unknown servers covertly.</span><span class='qd'><b>The screen brightness is too high</b>: Brightness affects battery, not network traffic.</span><span class='qd'><b>The ringtone volume is too low</b>: Irrelevant to data transmission.</span>" },
{ id:"D3-033", domain:3, obj:"3.5", diff:"medium", q:"Which combination of symptoms BEST indicates a mobile device is infected with malware rather than simply aging?", options:["Sudden high data usage, unexpected battery drain, and connections to unfamiliar servers","Slightly slower charging and a smaller battery capacity over years","A scratched screen and a faded case","A loose volume button"], answer:0, explain:"<strong>Sudden high data usage, unexpected battery drain, and connections to unfamiliar servers</strong> is correct because these together point to malicious software actively running and communicating, not normal aging.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slightly slower charging and a smaller battery capacity over years</b>: Normal battery wear.</span><span class='qd'><b>A scratched screen and a faded case</b>: Cosmetic wear.</span><span class='qd'><b>A loose volume button</b>: A mechanical issue, not malware.</span>" },
{ id:"D3-034", domain:3, obj:"3.5", diff:"medium", q:"A user installed a flashlight app that requested access to contacts, SMS, and location. Now the phone shows high data use and friends report spam texts from the user. What is the BEST first action?", options:["Grant the app more permissions","Uninstall the over-permissioned app, revoke its access, and scan the device for malware","Buy more data","Turn the brightness down"], answer:1, explain:"<strong>Uninstall the over-permissioned app, revoke its access, and scan the device for malware</strong> is correct because a flashlight app demanding contacts/SMS/location and correlated spam indicates a malicious or fake app abusing permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grant the app more permissions</b>: This increases the risk and abuse.</span><span class='qd'><b>Buy more data</b>: Masks the symptom without removing the threat.</span><span class='qd'><b>Turn the brightness down</b>: Irrelevant to the security problem.</span>" },
{ id:"D3-035", domain:3, obj:"3.5", diff:"hard", q:"A user with an Android phone enabled installation from unknown sources and installed an app from a forum link. The phone is now sluggish, shows pop-up ads system-wide, and has unexplained data usage. What is the MOST likely root cause?", options:["A failing battery","A weak Wi-Fi signal","A malicious sideloaded app installed outside the official store","A cracked digitizer"], answer:2, explain:"<strong>A malicious sideloaded app installed outside the official store</strong> is correct because enabling unknown sources and sideloading from a forum bypasses store vetting, and the resulting symptoms indicate that app is malicious.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failing battery</b>: Does not cause system-wide ads or data spikes.</span><span class='qd'><b>A weak Wi-Fi signal</b>: Signal strength does not produce ads or extra data use.</span><span class='qd'><b>A cracked digitizer</b>: A touch-hardware fault, not malware.</span>" },
{ id:"D3-036", domain:3, obj:"3.5", diff:"easy", q:"Which mobile symptom MOST directly suggests unauthorized location tracking by an app?", options:["The clock is two minutes slow","The wallpaper changed","The keyboard sound is on","The location/GPS indicator stays active when no maps or navigation app is in use"], answer:3, explain:"<strong>The location/GPS indicator stays active when no maps or navigation app is in use</strong> is correct because a persistent location indicator with no legitimate app using it suggests background tracking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The clock is two minutes slow</b>: A time-sync issue, not tracking.</span><span class='qd'><b>The wallpaper changed</b>: A cosmetic change.</span><span class='qd'><b>The keyboard sound is on</b>: A sound setting, not a privacy indicator.</span>" },
{ id:"D3-037", domain:3, obj:"3.5", diff:"medium", q:"A user notices their phone's camera indicator dot lights up periodically when they are not taking photos, and an unfamiliar app is installed. What is the BEST immediate response?", options:["Investigate the app, revoke its camera permission, and remove it if it is not legitimate, then scan the device","Ignore it; the dot is decorative","Increase ringtone volume","Disable auto-rotate"], answer:0, explain:"<strong>Investigate the app, revoke its camera permission, and remove it if it is not legitimate, then scan the device</strong> is correct because unexpected camera activation tied to an unknown app indicates possible unauthorized camera access requiring permission revocation and removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore it; the dot is decorative</b>: The indicator signals active camera use, a real privacy concern.</span><span class='qd'><b>Increase ringtone volume</b>: Irrelevant to camera access.</span><span class='qd'><b>Disable auto-rotate</b>: A display setting, not a security control.</span>" },
{ id:"D3-038", domain:3, obj:"3.5", diff:"hard", q:"A user reports their phone frequently drops cellular signal in places it never used to, the device feels warm, and battery drains fast. Security software flags a recently installed app. What is the MOST likely explanation?", options:["The carrier permanently reduced coverage","A malicious app is consuming radio and CPU resources, causing power drain and intermittent signal loss","The screen protector blocks the antenna","The user enabled dark mode"], answer:1, explain:"<strong>A malicious app is consuming radio and CPU resources, causing power drain and intermittent signal loss</strong> is correct because a flagged app combined with heat, drain, and signal drops points to malware aggressively using device resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The carrier permanently reduced coverage</b>: That would not warm the device or drain the battery.</span><span class='qd'><b>The screen protector blocks the antenna</b>: Screen protectors do not cover cellular antennas in that way.</span><span class='qd'><b>The user enabled dark mode</b>: Dark mode would not cause these symptoms.</span>" },
{ id:"D3-039", domain:3, obj:"3.5", diff:"medium", q:"A user logs into their cloud account from the phone and sees recent sign-ins from a country they have never visited, plus app passwords they did not create. What is the BEST guidance?", options:["Wait and see if it happens again","Delete the email app","Treat the account as compromised: change the password from a trusted device, revoke unknown sessions/app passwords, and enable MFA","Increase screen timeout"], answer:2, explain:"<strong>Treat the account as compromised: change the password from a trusted device, revoke unknown sessions/app passwords, and enable MFA</strong> is correct because foreign sign-ins and unknown app passwords indicate unauthorized account access that must be secured immediately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wait and see if it happens again</b>: Delay allows continued misuse.</span><span class='qd'><b>Delete the email app</b>: Removing the app does not secure the account.</span><span class='qd'><b>Increase screen timeout</b>: Unrelated to account compromise.</span>" },
{ id:"D3-040", domain:3, obj:"3.5", diff:"medium", q:"A user downloaded a game that closely mimics a popular title but had very few reviews and an unofficial publisher. After installing, ads appear on the lock screen and data usage climbed. What is this MOST likely an example of?", options:["A legitimate sponsored game","A normal OS feature","A carrier billing app","A fake/counterfeit app delivering adware and consuming data"], answer:3, explain:"<strong>A fake/counterfeit app delivering adware and consuming data</strong> is correct because a low-reputation look-alike app with an unofficial publisher producing ads and data use is a fake app bundling adware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A legitimate sponsored game</b>: Legitimate titles do not push lock-screen ads from an unofficial publisher.</span><span class='qd'><b>A normal OS feature</b>: The OS does not inject third-party ads this way.</span><span class='qd'><b>A carrier billing app</b>: Carriers do not impersonate popular games.</span>" },
{ id:"D3-041", domain:3, obj:"3.5", diff:"hard", q:"A user reports their phone's microphone indicator turns on during a banking app session, and they later notice unauthorized transactions. Which BEST describes the likely chain of events?", options:["Malware or a malicious app captured sensitive input/audio, leading to leaked data and account misuse","The bank app legitimately recorded audio for support","The volume rocker is stuck","The phone overheated and rebooted"], answer:0, explain:"<strong>Malware or a malicious app captured sensitive input/audio, leading to leaked data and account misuse</strong> is correct because covert microphone activation during sensitive activity followed by fraud indicates data leakage via a malicious app.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The bank app legitimately recorded audio for support</b>: Banking apps do not covertly record during transactions, and it would not cause fraud.</span><span class='qd'><b>The volume rocker is stuck</b>: A mechanical button issue, not data leakage.</span><span class='qd'><b>The phone overheated and rebooted</b>: Thermal events do not enable the microphone or cause fraud.</span>" },
{ id:"D3-042", domain:3, obj:"3.5", diff:"medium", q:"A technician wants to reduce the chance a user's phone runs malicious apps. Which configuration BEST reduces the risk of sideloaded malware?", options:["Allow all unknown sources for convenience","Disable installation from unknown sources and install apps only from the official store","Disable the screen lock","Turn off automatic updates"], answer:1, explain:"<strong>Disable installation from unknown sources and install apps only from the official store</strong> is correct because blocking sideloading and using vetted official stores prevents most malicious app installs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow all unknown sources for convenience</b>: This increases sideloading risk.</span><span class='qd'><b>Disable the screen lock</b>: Weakens device security entirely.</span><span class='qd'><b>Turn off automatic updates</b>: Leaves the device unpatched and more vulnerable.</span>" },
{ id:"D3-043", domain:3, obj:"3.5", diff:"medium", q:"A user reports their phone has become sluggish and they receive frequent unexpected pop-ups, even outside any app. Which finding would BEST confirm adware is the cause?", options:["The battery is two years old","The phone has a screen protector","The pop-ups stop entirely after uninstalling a specific recently installed app","The storage is half full"], answer:2, explain:"<strong>The pop-ups stop entirely after uninstalling a specific recently installed app</strong> is correct because pop-ups ceasing after removing a particular app identifies that app as the adware source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The battery is two years old</b>: Battery age does not generate pop-ups.</span><span class='qd'><b>The phone has a screen protector</b>: A protector has no effect on software ads.</span><span class='qd'><b>The storage is half full</b>: Normal storage levels do not cause pop-ups.</span>" },
{ id:"D3-044", domain:3, obj:"3.5", diff:"hard", q:"After remediating a malware-infected phone by removing a malicious app, a technician wants to confirm no data leakage persists. Which check is MOST relevant?", options:["Confirm the wallpaper is restored","Check that the ringtone plays","Verify the brightness slider works","Review network/data usage for ongoing connections to unknown servers and audit app permissions"], answer:3, explain:"<strong>Review network/data usage for ongoing connections to unknown servers and audit app permissions</strong> is correct because verifying that suspicious outbound traffic has stopped and permissions are sane confirms the leakage path is closed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confirm the wallpaper is restored</b>: Cosmetic and unrelated to leakage.</span><span class='qd'><b>Check that the ringtone plays</b>: An audio check, not a security validation.</span><span class='qd'><b>Verify the brightness slider works</b>: A display test, irrelevant to data leakage.</span>" },
{ id:"D3-045", domain:3, obj:"3.5", diff:"medium", q:"A user's phone suddenly responds sluggishly and they receive a data-usage limit alert; a newly installed app is the top data consumer in settings. What is the BEST first action?", options:["Restrict that app's background data, review its permissions, and remove it if it is unnecessary or untrusted","Buy a higher data plan","Disable the lock screen","Lower the display resolution"], answer:0, explain:"<strong>Restrict that app's background data, review its permissions, and remove it if it is unnecessary or untrusted</strong> is correct because a new app topping data use alongside sluggishness points to it as the cause, addressed by restricting, auditing, and removing it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buy a higher data plan</b>: Hides the symptom without removing the cause.</span><span class='qd'><b>Disable the lock screen</b>: Weakens security and does not reduce data use.</span><span class='qd'><b>Lower the display resolution</b>: Does not affect data consumption.</span>" },
{ id:"D3-046", domain:3, obj:"3.2", diff:"medium", q:"A user reports that the browser opens to an unfamiliar search engine and many web searches redirect to ad-filled pages. The home page reverts even after being changed. What is the MOST likely cause?", options:["A failing hard drive","A browser hijacker / unwanted extension","An overheating CPU","A dead CMOS battery"], answer:1, explain:"<strong>A browser hijacker / unwanted extension</strong> is correct because persistent redirection and a forced search engine that reverts are classic signs of a browser hijacker installed as an extension or PUP.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failing hard drive</b>: Would cause data errors, not redirects.</span><span class='qd'><b>An overheating CPU</b>: Causes shutdowns, not search redirection.</span><span class='qd'><b>A dead CMOS battery</b>: Causes clock/BIOS issues, not browser behavior.</span>" },
{ id:"D3-047", domain:3, obj:"3.2", diff:"medium", q:"A user sees frequent pop-ups claiming the computer is infected and urging them to call a phone number or install a \"security cleaner.\" What does this MOST likely indicate?", options:["A legitimate Windows alert","A hardware fan failure","Rogue/fake antivirus and a scam pop-up; do not call or install","A printer driver problem"], answer:2, explain:"<strong>Rogue/fake antivirus and a scam pop-up; do not call or install</strong> is correct because fake infection warnings pressuring the user to call or install software are rogue antivirus scams.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A legitimate Windows alert</b>: Windows does not direct users to call phone numbers.</span><span class='qd'><b>A hardware fan failure</b>: Unrelated to pop-ups.</span><span class='qd'><b>A printer driver problem</b>: Does not produce infection pop-ups.</span>" },
{ id:"D3-048", domain:3, obj:"3.2", diff:"hard", q:"After visiting a website, a user's browser shows a certificate warning on many sites it never warned about before, including well-known ones. Local time is correct. Which cause should the technician suspect FIRST?", options:["The monitor needs calibration","The keyboard layout changed","The page file is too small","Malware installed a rogue root certificate or a proxy is intercepting traffic"], answer:3, explain:"<strong>Malware installed a rogue root certificate or a proxy is intercepting traffic</strong> is correct because sudden certificate warnings across many trusted sites, with correct time, suggest interception via a malicious root cert or proxy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The monitor needs calibration</b>: Display calibration cannot trigger cert warnings.</span><span class='qd'><b>The keyboard layout changed</b>: Input settings are unrelated.</span><span class='qd'><b>The page file is too small</b>: Memory paging does not affect TLS validation.</span>" },
{ id:"D3-049", domain:3, obj:"3.2", diff:"medium", q:"A user complains of constant desktop notifications advertising products even when no browser is open. Investigation shows an unknown program in startup. This is BEST classified as:", options:["Adware/PUP generating unwanted notifications","A normal Windows feature","A failed RAM module","A disk fragmentation issue"], answer:0, explain:"<strong>Adware/PUP generating unwanted notifications</strong> is correct because ads appearing without a browser plus an unknown startup program indicate adware or a potentially unwanted program.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A normal Windows feature</b>: Windows does not push product ads via unknown programs.</span><span class='qd'><b>A failed RAM module</b>: Causes crashes, not ads.</span><span class='qd'><b>A disk fragmentation issue</b>: Slows access, not notifications.</span>" },
{ id:"D3-050", domain:3, obj:"3.2", diff:"hard", q:"A user reports that critical Windows updates repeatedly fail to install with vague errors, and Windows Defender is mysteriously disabled and cannot be re-enabled. What is the MOST likely explanation?", options:["The user disabled the screensaver","Malware is blocking updates and disabling security to protect itself","The display driver is outdated","The mouse battery is low"], answer:1, explain:"<strong>Malware is blocking updates and disabling security to protect itself</strong> is correct because malware commonly blocks OS updates and disables antivirus to avoid detection and removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The user disabled the screensaver</b>: Screensaver settings are irrelevant.</span><span class='qd'><b>The display driver is outdated</b>: Does not disable Defender or block updates.</span><span class='qd'><b>The mouse battery is low</b>: Unrelated peripheral issue.</span>" },
{ id:"D3-051", domain:3, obj:"3.2", diff:"medium", q:"Coworkers report receiving spam emails from a user's address that the user did not send, and the user's sent folder contains unknown messages. What does this symptom indicate?", options:["A broken keyboard","An overheating GPU","A hijacked email account","A full recycle bin"], answer:2, explain:"<strong>A hijacked email account</strong> is correct because unknown sent messages and spam from the user's address are signs the account was compromised and is being used to send mail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A broken keyboard</b>: Cannot send emails on its own.</span><span class='qd'><b>An overheating GPU</b>: Unrelated to email.</span><span class='qd'><b>A full recycle bin</b>: Does not generate outgoing mail.</span>" },
{ id:"D3-052", domain:3, obj:"3.2", diff:"easy", q:"Which symptom is the clearest indicator of malware rather than a hardware fault?", options:["A loud, grinding hard drive","A flickering backlight","A swollen battery","Frequent random pop-ups and browser redirects to unknown sites"], answer:3, explain:"<strong>Frequent random pop-ups and browser redirects to unknown sites</strong> is correct because pop-ups and redirection are hallmark malware/adware symptoms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A loud, grinding hard drive</b>: A mechanical hardware failure.</span><span class='qd'><b>A flickering backlight</b>: A display hardware issue.</span><span class='qd'><b>A swollen battery</b>: A physical battery failure.</span>" },
{ id:"D3-053", domain:3, obj:"3.2", diff:"hard", q:"A technician finds that several Windows system files have unexpected modification dates and hashes that do not match the known-good versions, and the machine behaves erratically. What does this indicate?", options:["Altered/replaced system files consistent with a malware infection (possible rootkit)","Normal Windows updating","A scheduled defragmentation","A printer spooler reset"], answer:0, explain:"<strong>Altered/replaced system files consistent with a malware infection (possible rootkit)</strong> is correct because modified system files with mismatched hashes point to tampering by malware, possibly a rootkit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Normal Windows updating</b>: Updates are signed and would match known versions.</span><span class='qd'><b>A scheduled defragmentation</b>: Does not alter system file contents.</span><span class='qd'><b>A printer spooler reset</b>: Unrelated to system file integrity.</span>" },
{ id:"D3-054", domain:3, obj:"3.2", diff:"medium", q:"A user clicks an emailed link and now random pop-ups appear in the browser even on trusted sites, and a new toolbar was added. Which immediate action BEST limits further harm while you investigate?", options:["Open more websites to test","Disconnect from the network/quarantine the machine and remove the suspicious toolbar/extension","Increase the page file","Defragment the disk"], answer:1, explain:"<strong>Disconnect from the network/quarantine the machine and remove the suspicious toolbar/extension</strong> is correct because quarantining limits spread and data exfiltration while you remove the malicious add-on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Open more websites to test</b>: Increases exposure and risk.</span><span class='qd'><b>Increase the page file</b>: Irrelevant to a malware infection.</span><span class='qd'><b>Defragment the disk</b>: Does nothing to contain malware.</span>" },
{ id:"D3-055", domain:3, obj:"3.2", diff:"medium", q:"A browser displays warnings that a site's certificate is not trusted, but only on one specific internal company site that uses a private CA. Other sites are fine. What is the MOST likely benign explanation?", options:["The whole system is infected","The CPU is failing","The private CA root certificate is not installed/trusted on the client","The RAM is faulty"], answer:2, explain:"<strong>The private CA root certificate is not installed/trusted on the client</strong> is correct because a single internal site using a private CA will warn if the client lacks that CA's root in its trust store; this is a benign configuration issue.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The whole system is infected</b>: Only one internal site is affected, not all sites.</span><span class='qd'><b>The CPU is failing</b>: Hardware does not cause selective cert warnings.</span><span class='qd'><b>The RAM is faulty</b>: Memory faults do not produce single-site cert errors.</span>" },
{ id:"D3-056", domain:3, obj:"3.2", diff:"hard", q:"A user's antivirus shows a pop-up styled to look like the real product, but clicking it opens a website demanding payment to \"unlock full protection.\" The genuine antivirus console shows no such alert. What is happening?", options:["The real antivirus needs activation","Windows is updating","The browser cache is full","A rogue/fake antivirus is impersonating the legitimate product to extort payment"], answer:3, explain:"<strong>A rogue/fake antivirus is impersonating the legitimate product to extort payment</strong> is correct because a payment-demanding pop-up not reflected in the genuine console is rogue security software mimicking the real one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The real antivirus needs activation</b>: Genuine activation appears in the product's own console, not a web payment page.</span><span class='qd'><b>Windows is updating</b>: Updates do not demand payment.</span><span class='qd'><b>The browser cache is full</b>: Cache does not cause extortion pop-ups.</span>" },
{ id:"D3-057", domain:3, obj:"3.2", diff:"medium", q:"Which of the following is the BEST indicator that a pop-up is a fake antivirus alert rather than a real one?", options:["It appears in a web browser and pressures the user to call a number or pay immediately","It appears inside the antivirus application's own interface","It quietly logs to Event Viewer","It only shows after a reboot"], answer:0, explain:"<strong>It appears in a web browser and pressures the user to call a number or pay immediately</strong> is correct because legitimate antivirus alerts originate in the app, while browser-based, high-pressure call/pay prompts are scams.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It appears inside the antivirus application's own interface</b>: That suggests a genuine alert.</span><span class='qd'><b>It quietly logs to Event Viewer</b>: Legitimate logging is not a scam indicator.</span><span class='qd'><b>It only shows after a reboot</b>: Timing alone does not indicate a fake alert.</span>" },
{ id:"D3-058", domain:3, obj:"3.2", diff:"hard", q:"After cleaning a system, a user reports the browser still redirects searches. The technician checks installed extensions (clean) but finds an unexpected entry in the OS hosts file and a configured proxy. What do these findings suggest?", options:["The cleanup is complete","Residual malware artifacts (modified hosts file and proxy) are still redirecting traffic","A new monitor is needed","The disk needs defragmentation"], answer:1, explain:"<strong>Residual malware artifacts (modified hosts file and proxy) are still redirecting traffic</strong> is correct because malicious hosts-file entries and proxy settings can persist after extension removal and continue redirecting; they must be reverted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cleanup is complete</b>: Redirection persists, so it is not complete.</span><span class='qd'><b>A new monitor is needed</b>: Display hardware is irrelevant.</span><span class='qd'><b>The disk needs defragmentation</b>: Does not affect redirection.</span>" },
{ id:"D3-059", domain:3, obj:"3.2", diff:"medium", q:"A user notices their default search engine, new-tab page, and home page were all changed without their consent, and reverting them does not stick. Which category of threat is responsible?", options:["Ransomware","Keylogger","Browser hijacker","Worm"], answer:2, explain:"<strong>Browser hijacker</strong> is correct because changing and re-enforcing search, new-tab, and home page settings is the defining behavior of a browser hijacker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ransomware</b>: Encrypts files and demands payment, not browser settings.</span><span class='qd'><b>Keylogger</b>: Records keystrokes silently.</span><span class='qd'><b>Worm</b>: Self-propagates across networks; it does not specifically alter browser pages.</span>" },
{ id:"D3-060", domain:3, obj:"3.2", diff:"medium", q:"A user reports that Windows Update keeps failing and an unfamiliar program reappears after deletion. Combined, these symptoms MOST strongly suggest:", options:["A failing power supply","A loose SATA cable","A dim display backlight","A malware infection with persistence that blocks updates"], answer:3, explain:"<strong>A malware infection with persistence that blocks updates</strong> is correct because update failures plus a program that re-creates itself after deletion indicate persistent malware defending itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failing power supply</b>: Causes power issues, not self-reinstalling programs.</span><span class='qd'><b>A loose SATA cable</b>: Causes drive errors, not update blocking.</span><span class='qd'><b>A dim display backlight</b>: A display hardware symptom.</span>" },
{ id:"D3-061", domain:3, obj:"3.2", diff:"hard", q:"A user's contacts report receiving phishing messages from the user's social and email accounts simultaneously, and the user finds password-reset emails they did not request. What is the BEST immediate guidance?", options:["Treat accounts as compromised: change passwords from a clean device and enable MFA","Ignore it; it is spam","Buy a new monitor","Defragment the drive"], answer:0, explain:"<strong>Treat accounts as compromised: change passwords from a clean device and enable MFA</strong> is correct because multi-account abuse and unsolicited reset emails indicate credential compromise that requires securing accounts immediately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore it; it is spam</b>: Active misuse of the accounts is not harmless spam.</span><span class='qd'><b>Buy a new monitor</b>: Hardware is unrelated.</span><span class='qd'><b>Defragment the drive</b>: Does nothing for compromised accounts.</span>" },
{ id:"D3-062", domain:3, obj:"3.2", diff:"medium", q:"A web page suddenly opens many cascading pop-up windows that reappear when closed, making the browser hard to use. What is the SAFEST first step?", options:["Click any \"Download\" buttons in the pop-ups","Close the browser via Task Manager and avoid interacting with the pop-up content","Enter credit card details to dismiss them","Disable the antivirus"], answer:1, explain:"<strong>Close the browser via Task Manager and avoid interacting with the pop-up content</strong> is correct because force-closing the browser stops the loop without clicking malicious elements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Click any \"Download\" buttons in the pop-ups</b>: This installs malware.</span><span class='qd'><b>Enter credit card details to dismiss them</b>: A scam that exposes financial data.</span><span class='qd'><b>Disable the antivirus</b>: Removes protection during an attack.</span>" },
{ id:"D3-063", domain:3, obj:"3.2", diff:"easy", q:"A genuine browser certificate warning that says the connection is not private and the certificate has expired MOST directly indicates:", options:["The CPU is overclocked","The RAM is failing","The site's TLS certificate is invalid, expired, or untrusted","The printer is offline"], answer:2, explain:"<strong>The site's TLS certificate is invalid, expired, or untrusted</strong> is correct because certificate warnings report problems with the site's certificate validity or trust chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The CPU is overclocked</b>: Unrelated to TLS.</span><span class='qd'><b>The RAM is failing</b>: Memory faults do not produce cert warnings.</span><span class='qd'><b>The printer is offline</b>: Printing is irrelevant to browsing certificates.</span>" },
{ id:"D3-064", domain:3, obj:"3.2", diff:"medium", q:"A user's machine shows altered system files and the security software warns of integrity violations. Before remediation, why is verifying and documenting the symptoms important?", options:["It is not important; just delete files","It speeds up the GPU","It frees disk space","Confirming symptoms ensures accurate diagnosis and proper remediation, and avoids deleting legitimate files"], answer:3, explain:"<strong>Confirming symptoms ensures accurate diagnosis and proper remediation, and avoids deleting legitimate files</strong> is correct because verifying symptoms first prevents misdiagnosis and accidental removal of needed files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is not important; just delete files</b>: Blind deletion can break the OS.</span><span class='qd'><b>It speeds up the GPU</b>: Irrelevant to malware handling.</span><span class='qd'><b>It frees disk space</b>: Not the purpose of symptom verification.</span>" },
{ id:"D3-065", domain:3, obj:"3.2", diff:"hard", q:"A technician notices that a user's banking website now prompts for unusual information (full SSN, PIN) on a page that looks slightly off, and the URL is subtly misspelled. What is occurring?", options:["A phishing/pharming attack tricking the user into revealing sensitive data","A normal bank policy update","A Windows update","A driver rollback"], answer:0, explain:"<strong>A phishing/pharming attack tricking the user into revealing sensitive data</strong> is correct because a look-alike page on a misspelled URL requesting excessive sensitive data is a phishing or pharming attack.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A normal bank policy update</b>: Legitimate banks do not request PINs/SSNs on a misspelled domain.</span><span class='qd'><b>A Windows update</b>: Unrelated to web page content.</span><span class='qd'><b>A driver rollback</b>: Has nothing to do with website prompts.</span>" },
{ id:"D3-066", domain:3, obj:"3.2", diff:"medium", q:"Which finding would BEST confirm that frequent pop-ups are caused by a malicious browser extension rather than a website?", options:["The pop-ups appear only on one trusted news site","The pop-ups stop when the network cable is unplugged but resume when reconnected to any site, and disabling a specific extension stops them entirely","The pop-ups stop after closing one tab","The pop-ups appear only in full-screen video"], answer:1, explain:"<strong>The pop-ups stop when the network cable is unplugged but resume when reconnected to any site, and disabling a specific extension stops them entirely</strong> is correct because pop-ups across all sites that cease when one extension is disabled point to that extension as the source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The pop-ups appear only on one trusted news site</b>: That suggests the site, not an extension.</span><span class='qd'><b>The pop-ups stop after closing one tab</b>: Indicates a single page is responsible.</span><span class='qd'><b>The pop-ups appear only in full-screen video</b>: Points to a media player or site behavior.</span>" },
{ id:"D3-067", domain:3, obj:"3.3", diff:"medium", q:"According to CompTIA's best-practice malware removal procedure, what is the FIRST step?", options:["Quarantine the infected system","Disable System Restore in Windows","Investigate and verify malware symptoms","Educate the end user"], answer:2, explain:"<strong>Investigate and verify malware symptoms</strong> is correct because step 1 is to confirm an infection actually exists before taking further action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quarantine the infected system</b>: That is step 2, after verifying symptoms.</span><span class='qd'><b>Disable System Restore in Windows</b>: That is step 3.</span><span class='qd'><b>Educate the end user</b>: That is the final step.</span>" },
{ id:"D3-068", domain:3, obj:"3.3", diff:"medium", q:"In the malware removal best-practice procedure, what step immediately FOLLOWS investigating and verifying the malware symptoms?", options:["Remediate the infected system","Schedule scans and run updates","Enable System Restore and create a restore point","Quarantine the infected system"], answer:3, explain:"<strong>Quarantine the infected system</strong> is correct because step 2 is to isolate the machine from the network to prevent spread before any cleanup.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Remediate the infected system</b>: That is step 4.</span><span class='qd'><b>Schedule scans and run updates</b>: That is step 5.</span><span class='qd'><b>Enable System Restore and create a restore point</b>: That is step 6.</span>" },
{ id:"D3-069", domain:3, obj:"3.3", diff:"medium", q:"Why does the best-practice procedure call for disabling System Restore in Windows before remediating malware?", options:["To prevent restore points that contain the infection from reinfecting the system","To speed up the CPU","To free RAM","To improve the display"], answer:0, explain:"<strong>To prevent restore points that contain the infection from reinfecting the system</strong> is correct because malware can hide in restore points, so disabling System Restore (step 3) purges them so cleaning is not undone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To speed up the CPU</b>: Performance is not the goal.</span><span class='qd'><b>To free RAM</b>: Memory is unrelated to this step.</span><span class='qd'><b>To improve the display</b>: Irrelevant to malware removal.</span>" },
{ id:"D3-070", domain:3, obj:"3.3", diff:"hard", q:"A technician has verified an infection and isolated the machine from the network. Following the best-practice order, which TWO actions come next, and in what sequence?", options:["Educate the user, then quarantine","Disable System Restore, then remediate (update anti-malware, scan and remove)","Create a restore point, then schedule scans","Reimage, then verify symptoms"], answer:1, explain:"<strong>Disable System Restore, then remediate (update anti-malware, scan and remove)</strong> is correct because after quarantine (step 2) you disable System Restore (step 3) and then remediate (step 4).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Educate the user, then quarantine</b>: Education is last and quarantine already happened.</span><span class='qd'><b>Create a restore point, then schedule scans</b>: Those are steps 6 and 5 and out of order here.</span><span class='qd'><b>Reimage, then verify symptoms</b>: Verification is step 1 and already done.</span>" },
{ id:"D3-071", domain:3, obj:"3.3", diff:"medium", q:"During the remediation step (step 4) of the malware removal procedure, what must a technician do BEFORE running the scan?", options:["Re-enable System Restore","Educate the end user","Update the anti-malware software/definitions","Create a restore point"], answer:2, explain:"<strong>Update the anti-malware software/definitions</strong> is correct because step 4 requires updating anti-malware first so the scan can detect the latest threats before scanning and removing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Re-enable System Restore</b>: That occurs at step 6, after cleaning.</span><span class='qd'><b>Educate the end user</b>: That is the final step.</span><span class='qd'><b>Create a restore point</b>: That is part of step 6.</span>" },
{ id:"D3-072", domain:3, obj:"3.3", diff:"hard", q:"After successfully scanning and removing malware, the technician wants to ensure the threat does not return and the system stays protected. According to step 5, what should be done?", options:["Disable the antivirus","Reformat the drive","Educate the user immediately and stop","Schedule recurring scans and enable automatic updates"], answer:3, explain:"<strong>Schedule recurring scans and enable automatic updates</strong> is correct because step 5 sets up scheduled scans and updates to maintain protection going forward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disable the antivirus</b>: That removes ongoing protection.</span><span class='qd'><b>Reformat the drive</b>: Not part of this step and unnecessary after successful removal.</span><span class='qd'><b>Educate the user immediately and stop</b>: Education is step 7 and comes after re-enabling System Restore.</span>" },
{ id:"D3-073", domain:3, obj:"3.3", diff:"medium", q:"At which point in the best-practice malware removal procedure should System Restore be RE-ENABLED and a fresh restore point created?", options:["Step 6, after remediation and scheduling scans are complete","Step 1, during symptom verification","Step 2, during quarantine","Before disabling System Restore"], answer:0, explain:"<strong>Step 6, after remediation and scheduling scans are complete</strong> is correct because System Restore is re-enabled and a clean restore point created only after the system is verified clean.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Step 1, during symptom verification</b>: System Restore is not yet disabled at that point.</span><span class='qd'><b>Step 2, during quarantine</b>: Re-enabling before cleaning could capture the infection.</span><span class='qd'><b>Before disabling System Restore</b>: This is illogical; you disable it first, then re-enable after cleanup.</span>" },
{ id:"D3-074", domain:3, obj:"3.3", diff:"easy", q:"What is the FINAL step in the best-practice malware removal procedure?", options:["Quarantine the system","Educate the end user","Disable System Restore","Update anti-malware definitions"], answer:1, explain:"<strong>Educate the end user</strong> is correct because step 7 teaches the user safe habits to prevent reinfection, completing the process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quarantine the system</b>: That is step 2.</span><span class='qd'><b>Disable System Restore</b>: That is step 3.</span><span class='qd'><b>Update anti-malware definitions</b>: That is part of step 4.</span>" },
{ id:"D3-075", domain:3, obj:"3.3", diff:"hard", q:"Place these malware removal actions in the correct best-practice order: (W) create a restore point, (X) quarantine, (Y) scan and remove, (Z) verify symptoms.", options:["X, Z, Y, W","Y, X, Z, W","Z, X, Y, W","W, Z, X, Y"], answer:2, explain:"<strong>Z, X, Y, W</strong> is correct because the order is verify symptoms (Z), quarantine (X), then remediate/scan and remove (Y), and later create a restore point after re-enabling System Restore (W).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>X, Z, Y, W</b>: Quarantine cannot precede verifying symptoms.</span><span class='qd'><b>Y, X, Z, W</b>: You cannot scan and remove before verifying and quarantining.</span><span class='qd'><b>W, Z, X, Y</b>: A restore point is created last, not first.</span>" },
{ id:"D3-076", domain:3, obj:"3.3", diff:"medium", q:"A technician quarantines an infected laptop. What is the PRIMARY purpose of this quarantine step?", options:["To delete user files","To increase the page file","To update the BIOS","To isolate the system and prevent the malware from spreading to other devices"], answer:3, explain:"<strong>To isolate the system and prevent the malware from spreading to other devices</strong> is correct because quarantine (step 2) disconnects the machine to contain the infection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To delete user files</b>: Quarantine isolates; it does not delete data.</span><span class='qd'><b>To increase the page file</b>: Unrelated to containment.</span><span class='qd'><b>To update the BIOS</b>: Not part of the procedure.</span>" },
{ id:"D3-077", domain:3, obj:"3.3", diff:"hard", q:"A junior tech re-enabled System Restore and created a restore point immediately after disabling it, before scanning. Why is this a problem?", options:["The restore point may capture the still-infected state, allowing reinfection later","It is not a problem; order does not matter","It deletes the antivirus","It overheats the CPU"], answer:0, explain:"<strong>The restore point may capture the still-infected state, allowing reinfection later</strong> is correct because re-enabling and snapshotting before cleaning preserves the malware in a restore point, defeating the procedure's purpose.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is not a problem; order does not matter</b>: The defined order specifically prevents this.</span><span class='qd'><b>It deletes the antivirus</b>: System Restore does not remove antivirus.</span><span class='qd'><b>It overheats the CPU</b>: Unrelated to thermals.</span>" },
{ id:"D3-078", domain:3, obj:"3.3", diff:"medium", q:"Which action belongs to the remediation step (step 4) of the malware removal best practice?", options:["Educating the user about phishing","Updating anti-malware software, then scanning and removing the malware","Quarantining the device","Verifying the symptoms"], answer:1, explain:"<strong>Updating anti-malware software, then scanning and removing the malware</strong> is correct because step 4 remediation is to update the tools and then scan and remove the infection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Educating the user about phishing</b>: That is step 7.</span><span class='qd'><b>Quarantining the device</b>: That is step 2.</span><span class='qd'><b>Verifying the symptoms</b>: That is step 1.</span>" },
{ id:"D3-079", domain:3, obj:"3.3", diff:"hard", q:"A technician completed scanning and removal but skipped scheduling scans/updates and went straight to re-enabling System Restore and educating the user. Which best-practice step was omitted, and where did it belong?", options:["Step 2 (quarantine), belonged before remediation","Step 1 (verify symptoms), belonged at the end","Step 5 (schedule scans and run updates), belonged after remediation and before re-enabling System Restore","Step 7 (educate user), belonged first"], answer:2, explain:"<strong>Step 5 (schedule scans and run updates), belonged after remediation and before re-enabling System Restore</strong> is correct because the order is remediate (4), schedule scans and updates (5), enable System Restore and create a point (6), educate (7).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Step 2 (quarantine), belonged before remediation</b>: Quarantine was already done earlier.</span><span class='qd'><b>Step 1 (verify symptoms), belonged at the end</b>: Verification is first, not last.</span><span class='qd'><b>Step 7 (educate user), belonged first</b>: Education is the final step.</span>" },
{ id:"D3-080", domain:3, obj:"3.3", diff:"medium", q:"Educating the end user as the last step of malware removal MOST directly aims to:", options:["Increase system RAM","Speed up the disk","Update the BIOS firmware","Reduce the likelihood of reinfection by teaching safe practices"], answer:3, explain:"<strong>Reduce the likelihood of reinfection by teaching safe practices</strong> is correct because user education on safe habits helps prevent the same infection from recurring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase system RAM</b>: Education does not change hardware.</span><span class='qd'><b>Speed up the disk</b>: Unrelated to user training.</span><span class='qd'><b>Update the BIOS firmware</b>: Not a goal of education.</span>" },
{ id:"D3-081", domain:3, obj:"3.3", diff:"hard", q:"During remediation, an updated scan removes the threat but the machine reboots into the malware again. Stepping back, which earlier best-practice step most likely failed and should be revisited?", options:["Disabling System Restore (step 3), since restore points may still contain the malware","Educating the user","Scheduling scans","Creating a restore point"], answer:0, explain:"<strong>Disabling System Restore (step 3), since restore points may still contain the malware</strong> is correct because if System Restore was not disabled, infected restore points can reintroduce the malware after removal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Educating the user</b>: Education does not cause reinfection on reboot.</span><span class='qd'><b>Scheduling scans</b>: Scheduling future scans does not reinfect the system.</span><span class='qd'><b>Creating a restore point</b>: That comes later and would not reintroduce malware if done after cleaning.</span>" },
{ id:"D3-082", domain:3, obj:"3.3", diff:"medium", q:"Which sequence correctly represents steps 4 through 7 of the best-practice malware removal procedure?", options:["Quarantine; remediate; educate; verify","Remediate; schedule scans and run updates; enable System Restore and create a restore point; educate the end user","Verify; quarantine; disable System Restore; remediate","Educate; schedule scans; remediate; quarantine"], answer:1, explain:"<strong>Remediate; schedule scans and run updates; enable System Restore and create a restore point; educate the end user</strong> is correct because steps 4 to 7 are remediate, schedule scans/updates, enable System Restore and create a point, then educate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Quarantine; remediate; educate; verify</b>: Mixes early and late steps out of order.</span><span class='qd'><b>Verify; quarantine; disable System Restore; remediate</b>: These are steps 1 to 4, not 4 to 7.</span><span class='qd'><b>Educate; schedule scans; remediate; quarantine</b>: Completely reverses the order.</span>" },
{ id:"D3-083", domain:3, obj:"3.3", diff:"hard", q:"A technician argues that quarantine can be skipped for a single home PC not on a network. Per best practice, what is the BEST response?", options:["Agree and skip all steps","Skip verification too","Quarantine still applies: isolate the device (including removable media and any connectivity) to prevent spread and exfiltration before cleaning","Reimage without scanning"], answer:2, explain:"<strong>Quarantine still applies: isolate the device (including removable media and any connectivity) to prevent spread and exfiltration before cleaning</strong> is correct because quarantine guards against spread via USB drives and any network/Internet connection, so it remains step 2 regardless.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Agree and skip all steps</b>: The procedure exists to ensure thorough, safe removal.</span><span class='qd'><b>Skip verification too</b>: Verifying symptoms is essential first.</span><span class='qd'><b>Reimage without scanning</b>: Not the prescribed remediation path and skips containment.</span>" },
{ id:"D3-084", domain:3, obj:"3.3", diff:"medium", q:"A technician is documenting the malware removal for the ticket. Which step's outcome should be recorded to show the system was returned to a protected, recoverable state?", options:["That symptoms were only suspected","That the network was left connected during cleaning","That scans were disabled","That System Restore was re-enabled and a clean restore point was created (step 6)"], answer:3, explain:"<strong>That System Restore was re-enabled and a clean restore point was created (step 6)</strong> is correct because re-enabling System Restore and creating a clean restore point documents that recovery protection was restored after cleaning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That symptoms were only suspected</b>: Symptoms must be verified, not just suspected.</span><span class='qd'><b>That the network was left connected during cleaning</b>: That violates quarantine.</span><span class='qd'><b>That scans were disabled</b>: The opposite of best practice.</span>" },
{ id:"D3-085", domain:3, obj:"3.3", diff:"hard", q:"Order these steps correctly: (1) enable System Restore and create a restore point, (2) disable System Restore, (3) schedule scans and run updates, (4) remediate (scan and remove).", options:["2, 4, 3, 1","1, 2, 3, 4","4, 2, 1, 3","3, 1, 4, 2"], answer:0, explain:"<strong>2, 4, 3, 1</strong> is correct because you disable System Restore (step 3 of the full list), remediate (step 4), schedule scans and updates (step 5), then enable System Restore and create a restore point (step 6).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>1, 2, 3, 4</b>: You cannot enable a restore point before disabling System Restore and cleaning.</span><span class='qd'><b>4, 2, 1, 3</b>: Disabling System Restore must precede remediation.</span><span class='qd'><b>3, 1, 4, 2</b>: Completely out of sequence.</span>" },
{ id:"D3-086", domain:3, obj:"3.3", diff:"medium", q:"Which statement BEST explains why the malware removal steps must be performed in their defined order?", options:["The order is arbitrary and only for documentation","Each step depends on the previous; skipping or reordering can cause reinfection or incomplete removal","Order only matters on servers","Order only affects performance"], answer:1, explain:"<strong>Each step depends on the previous; skipping or reordering can cause reinfection or incomplete removal</strong> is correct because the sequence (verify, quarantine, disable restore, remediate, schedule, re-enable restore, educate) is designed so each step builds safely on the last.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The order is arbitrary and only for documentation</b>: The order is functional, not cosmetic.</span><span class='qd'><b>Order only matters on servers</b>: It applies to all systems.</span><span class='qd'><b>Order only affects performance</b>: Performance is not the concern; effective removal is.</span>" },
{ id:"D3-087", domain:3, obj:"3.3", diff:"easy", q:"In the malware removal procedure, which step number corresponds to remediation (updating anti-malware and then scanning and removing)?", options:["Step 2","Step 6","Step 4","Step 7"], answer:2, explain:"<strong>Step 4</strong> is correct because remediation (update anti-malware, then scan and remove) is the fourth step in the seven-step procedure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Step 2</b>: That is quarantine.</span><span class='qd'><b>Step 6</b>: That is enabling System Restore and creating a restore point.</span><span class='qd'><b>Step 7</b>: That is educating the end user.</span>" },
{ id:"D3-088", domain:3, obj:"3.4", diff:"medium", q:"A user reports their smartphone is hot to the touch and the battery drains rapidly even when idle. Which is the BEST first troubleshooting step?", options:["Replace the screen","Factory reset immediately","Buy a new phone","Check for a runaway app using high CPU/battery in battery settings and close or update it"], answer:3, explain:"<strong>Check for a runaway app using high CPU/battery in battery settings and close or update it</strong> is correct because overheating with rapid drain often traces to a misbehaving app, which battery usage stats can identify.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the screen</b>: The display is not the cause of drain.</span><span class='qd'><b>Factory reset immediately</b>: Too drastic before identifying the app.</span><span class='qd'><b>Buy a new phone</b>: Premature without diagnosis.</span>" },
{ id:"D3-089", domain:3, obj:"3.4", diff:"medium", q:"A mobile app crashes immediately on launch after the user updated it. Other apps work fine. What is the BEST first step?", options:["Force stop and clear the app's cache, then update or reinstall the app","Replace the battery","Factory reset the phone","Disable Wi-Fi permanently"], answer:0, explain:"<strong>Force stop and clear the app's cache, then update or reinstall the app</strong> is correct because clearing cache and reinstalling resolves most post-update app crashes without affecting the whole device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the battery</b>: Unrelated to an app crash.</span><span class='qd'><b>Factory reset the phone</b>: Excessive for one app.</span><span class='qd'><b>Disable Wi-Fi permanently</b>: Does not fix the app and breaks connectivity.</span>" },
{ id:"D3-090", domain:3, obj:"3.4", diff:"hard", q:"A user's phone is sluggish, apps lag, and storage shows nearly full. Performance improves briefly after a reboot then degrades again. Which is the MOST effective remedy?", options:["Increase screen brightness","Free storage by clearing caches and removing unused apps/media, since low free space slows the device","Disable the SIM","Turn off Bluetooth"], answer:1, explain:"<strong>Free storage by clearing caches and removing unused apps/media, since low free space slows the device</strong> is correct because near-full storage degrades mobile performance, and reclaiming space restores responsiveness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase screen brightness</b>: Does not affect performance.</span><span class='qd'><b>Disable the SIM</b>: Stops cellular service without fixing speed.</span><span class='qd'><b>Turn off Bluetooth</b>: Minor power impact, not the cause of lag.</span>" },
{ id:"D3-091", domain:3, obj:"3.4", diff:"medium", q:"A user reports there is no sound during calls or media even though the volume is up. The phone is not in silent mode. What is a reasonable next check?", options:["Update the OS only","Replace the SIM","Check whether Bluetooth is routing audio to a paired device and disconnect/clear it","Disable mobile data"], answer:2, explain:"<strong>Check whether Bluetooth is routing audio to a paired device and disconnect/clear it</strong> is correct because audio silently routing to a forgotten Bluetooth device is a common cause of no sound from the phone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Update the OS only</b>: Less likely than a misrouted audio path.</span><span class='qd'><b>Replace the SIM</b>: The SIM does not control audio output.</span><span class='qd'><b>Disable mobile data</b>: Unrelated to audio routing.</span>" },
{ id:"D3-092", domain:3, obj:"3.4", diff:"medium", q:"A user complains their phone screen is very dim and hard to read outdoors. Adaptive brightness is on. What should the technician check FIRST?", options:["The cellular signal strength","The storage capacity","The Bluetooth pairing","Whether auto-brightness/ambient sensor is malfunctioning or a screen protector covers the light sensor; try disabling auto-brightness and raising brightness manually"], answer:3, explain:"<strong>Whether auto-brightness/ambient sensor is malfunctioning or a screen protector covers the light sensor; try disabling auto-brightness and raising brightness manually</strong> is correct because a dim display with adaptive brightness often stems from sensor issues or coverings, testable by switching to manual brightness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The cellular signal strength</b>: Signal does not affect brightness.</span><span class='qd'><b>The storage capacity</b>: Storage does not control display brightness.</span><span class='qd'><b>The Bluetooth pairing</b>: Unrelated to the screen.</span>" },
{ id:"D3-093", domain:3, obj:"3.4", diff:"hard", q:"A tablet is completely frozen: the screen does not respond to touch and no buttons seem to work. What is the recommended action?", options:["Perform a forced restart (hardware button combination) to reboot the device","Wait several days for it to recover","Replace the logic board","Reformat the SD card"], answer:0, explain:"<strong>Perform a forced restart (hardware button combination) to reboot the device</strong> is correct because a forced restart is the standard recovery for an unresponsive, frozen mobile device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wait several days for it to recover</b>: A frozen device will not fix itself.</span><span class='qd'><b>Replace the logic board</b>: Far too drastic before a simple reboot.</span><span class='qd'><b>Reformat the SD card</b>: Does not unfreeze the OS.</span>" },
{ id:"D3-094", domain:3, obj:"3.4", diff:"medium", q:"An app repeatedly fails to update from the store, showing an error. Other apps update fine. Which is the BEST first action?", options:["Factory reset the device","Clear the store app's cache/data and retry, and confirm sufficient storage and a stable connection","Replace the battery","Disable location services"], answer:1, explain:"<strong>Clear the store app's cache/data and retry, and confirm sufficient storage and a stable connection</strong> is correct because store update failures are commonly fixed by clearing the store cache and ensuring space and connectivity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Factory reset the device</b>: Excessive for a single update failure.</span><span class='qd'><b>Replace the battery</b>: Battery is unrelated to app updates.</span><span class='qd'><b>Disable location services</b>: Does not affect app updating.</span>" },
{ id:"D3-095", domain:3, obj:"3.4", diff:"hard", q:"A phone overheats and throttles performance specifically while charging and using GPS navigation. The battery health reads normal. What is the MOST likely cause and best advice?", options:["A failed display panel; replace it","A corrupt SIM; replace it","Combined heat from charging plus intensive GPS/CPU use; remove the case, avoid use while fast-charging, and let it cool","A full mailbox; delete emails"], answer:2, explain:"<strong>Combined heat from charging plus intensive GPS/CPU use; remove the case, avoid use while fast-charging, and let it cool</strong> is correct because simultaneous fast charging and heavy GPS/CPU load generate heat that triggers throttling; reducing load and improving cooling helps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failed display panel; replace it</b>: The panel does not cause charging-related heat.</span><span class='qd'><b>A corrupt SIM; replace it</b>: The SIM does not generate heat.</span><span class='qd'><b>A full mailbox; delete emails</b>: Email storage does not cause overheating.</span>" },
{ id:"D3-096", domain:3, obj:"3.4", diff:"medium", q:"A user's phone keeps dropping Wi-Fi and switching to cellular at home. Other devices on the same Wi-Fi are stable. What is a reasonable first step on the phone?", options:["Factory reset immediately","Replace the antenna","Disable the camera","Forget the Wi-Fi network and rejoin it, and toggle Wi-Fi/airplane mode to reset the radio"], answer:3, explain:"<strong>Forget the Wi-Fi network and rejoin it, and toggle Wi-Fi/airplane mode to reset the radio</strong> is correct because re-establishing the saved network and resetting the radio resolves many single-device Wi-Fi drop issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Factory reset immediately</b>: Too drastic for a connectivity glitch.</span><span class='qd'><b>Replace the antenna</b>: Premature when other devices work.</span><span class='qd'><b>Disable the camera</b>: Unrelated to Wi-Fi.</span>" },
{ id:"D3-097", domain:3, obj:"3.4", diff:"hard", q:"After an OS update, a user reports much faster battery drain and warmth even when idle. Which step BEST isolates whether the update or a specific app is responsible?", options:["Reboot, then review battery usage by app and check for an app stuck in the background; if none, consider the update and look for a patch","Replace the battery first","Disable mobile data permanently","Turn off the screen entirely"], answer:0, explain:"<strong>Reboot, then review battery usage by app and check for an app stuck in the background; if none, consider the update and look for a patch</strong> is correct because reviewing per-app battery usage distinguishes a misbehaving app from an OS-update regression that may need a patch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the battery first</b>: Skips diagnosis of the software cause.</span><span class='qd'><b>Disable mobile data permanently</b>: Cripples the phone without isolating the cause.</span><span class='qd'><b>Turn off the screen entirely</b>: Not a diagnostic step.</span>" },
{ id:"D3-098", domain:3, obj:"3.4", diff:"medium", q:"A mobile app runs slowly and occasionally freezes, but works fine after the user closes other recently used apps. What does this suggest?", options:["The display is failing","Insufficient available memory/resources due to too many background apps","The SIM is defective","The charger is faulty"], answer:1, explain:"<strong>Insufficient available memory/resources due to too many background apps</strong> is correct because improvement after closing other apps indicates resource contention from background processes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The display is failing</b>: Display faults do not improve by closing apps.</span><span class='qd'><b>The SIM is defective</b>: The SIM does not affect app memory.</span><span class='qd'><b>The charger is faulty</b>: Charging is unrelated to app speed.</span>" },
{ id:"D3-099", domain:3, obj:"3.4", diff:"medium", q:"A user cannot hear the caller, but speakerphone works fine. Which component is the MOST likely culprit?", options:["The Wi-Fi radio","The GPS module","The earpiece speaker or its blocked grille","The fingerprint sensor"], answer:2, explain:"<strong>The earpiece speaker or its blocked grille</strong> is correct because audio working on speakerphone but not the earpiece points to the earpiece speaker or a debris-blocked grille.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The Wi-Fi radio</b>: Networking does not control earpiece audio.</span><span class='qd'><b>The GPS module</b>: Location hardware is unrelated to sound.</span><span class='qd'><b>The fingerprint sensor</b>: Biometrics do not affect audio.</span>" },
{ id:"D3-100", domain:3, obj:"3.4", diff:"hard", q:"A user reports the phone becomes unusably slow each afternoon and warm, coinciding with a fitness app's auto-sync. Battery health is good. Which is the BEST corrective action?", options:["Replace the phone","Disable the microphone","Lower the ringtone volume","Adjust or disable that app's background activity/sync and update the app, monitoring temperature and performance"], answer:3, explain:"<strong>Adjust or disable that app's background activity/sync and update the app, monitoring temperature and performance</strong> is correct because the symptoms correlate with one app's sync, so limiting its background activity and updating it addresses the cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replace the phone</b>: Unwarranted when a specific app is implicated.</span><span class='qd'><b>Disable the microphone</b>: Unrelated to background sync load.</span><span class='qd'><b>Lower the ringtone volume</b>: Does not affect performance or heat.</span>" },
{ id:"D3-101", domain:3, obj:"3.4", diff:"easy", q:"Which symptom is MOST characteristic of a mobile device that needs a forced restart rather than app-level troubleshooting?", options:["The entire device is frozen and unresponsive to touch and buttons","One app shows a login error","A single web page loads slowly","The wallpaper looks wrong"], answer:0, explain:"<strong>The entire device is frozen and unresponsive to touch and buttons</strong> is correct because a fully unresponsive system requires a forced restart, whereas app-specific issues are handled at the app level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One app shows a login error</b>: That is app-specific.</span><span class='qd'><b>A single web page loads slowly</b>: A network or browser symptom.</span><span class='qd'><b>The wallpaper looks wrong</b>: A cosmetic setting.</span>" },
{ id:"D3-102", domain:3, obj:"3.5", diff:"medium", q:"A user's phone shows unusually high network/data usage and receives a carrier notification that they are nearing their data limit, though their habits have not changed. What should the technician suspect?", options:["A failing screen","Malware or a rogue app transmitting data in the background","A weak battery","A cracked camera lens"], answer:1, explain:"<strong>Malware or a rogue app transmitting data in the background</strong> is correct because unexplained spikes in data usage are a classic sign of malware or a malicious app exfiltrating or downloading data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A failing screen</b>: A display fault does not consume data.</span><span class='qd'><b>A weak battery</b>: Battery health does not increase data usage.</span><span class='qd'><b>A cracked camera lens</b>: Physical damage does not transmit data.</span>" },
{ id:"D3-103", domain:3, obj:"3.5", diff:"hard", q:"A user installed an app from a third-party website (sideloaded) and now sees high data usage, fast battery drain, and the microphone indicator turning on unexpectedly. What is the MOST likely explanation?", options:["A normal system update","A failing speaker","A malicious sideloaded app abusing permissions (data exfiltration, microphone access)","A loose charging port"], answer:2, explain:"<strong>A malicious sideloaded app abusing permissions (data exfiltration, microphone access)</strong> is correct because sideloaded apps bypass store vetting, and these combined symptoms indicate the app is abusing permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A normal system update</b>: Updates do not covertly activate the microphone.</span><span class='qd'><b>A failing speaker</b>: Audio output is unrelated to data and mic abuse.</span><span class='qd'><b>A loose charging port</b>: Hardware does not cause permission abuse.</span>" },
{ id:"D3-104", domain:3, obj:"3.5", diff:"medium", q:"A user notices their phone's location indicator stays on even when no maps or navigation app is in use, and the battery drains faster than normal. Which security concern does this raise?", options:["The flashlight is stuck on","The volume is muted","The keyboard language changed","An app may be performing unauthorized location tracking in the background"], answer:3, explain:"<strong>An app may be performing unauthorized location tracking in the background</strong> is correct because a persistent location indicator with extra drain suggests an app is tracking location without legitimate need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The flashlight is stuck on</b>: That would drain battery but not relate to location.</span><span class='qd'><b>The volume is muted</b>: Unrelated to location or tracking.</span><span class='qd'><b>The keyboard language changed</b>: A cosmetic setting, not a security issue.</span>" },
{ id:"D3-105", domain:3, obj:"3.5", diff:"hard", q:"A user reports their email and cloud accounts on their phone show logins from unfamiliar locations, and friends received messages the user never sent. The phone also feels sluggish. Which combination of issues is MOST likely?", options:["Account compromise plus possible malware on the device; secure accounts and scan/clean the phone","A dead pixel and low storage","A loose SIM tray only","An outdated wallpaper"], answer:0, explain:"<strong>Account compromise plus possible malware on the device; secure accounts and scan/clean the phone</strong> is correct because unauthorized logins and sent messages indicate compromised accounts, and sluggishness suggests malware, so both must be addressed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A dead pixel and low storage</b>: Neither explains unauthorized account access.</span><span class='qd'><b>A loose SIM tray only</b>: Hardware seating does not cause account logins elsewhere.</span><span class='qd'><b>An outdated wallpaper</b>: Cosmetic and irrelevant.</span>" },
{ id:"D3-106", domain:3, obj:"3.5", diff:"medium", q:"A user downloaded what appeared to be a popular banking app, but it has a slightly different icon, requests excessive permissions, and is not from the official store. What is this MOST likely?", options:["A beta version from the bank","A fake/counterfeit app designed to steal credentials","A system theme","A required carrier app"], answer:1, explain:"<strong>A fake/counterfeit app designed to steal credentials</strong> is correct because a look-alike app outside the official store requesting excessive permissions is a classic fake app intended to harvest data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A beta version from the bank</b>: Legitimate betas come through official channels, not look-alikes.</span><span class='qd'><b>A system theme</b>: A theme would not impersonate a banking app.</span><span class='qd'><b>A required carrier app</b>: Carriers do not distribute counterfeit banking apps.</span>" },
{ id:"D3-107", domain:3, obj:"3.5", diff:"hard", q:"A corporate phone shows sluggish response, intermittent signal drops in areas with normally good coverage, and unexpected power drain. Security software flags outbound connections to unknown servers. What is the BEST conclusion?", options:["The carrier tower is down","The user needs a louder ringtone","The device is likely compromised by malware causing resource use and covert communication; isolate and remediate it","The SIM needs reactivation"], answer:2, explain:"<strong>The device is likely compromised by malware causing resource use and covert communication; isolate and remediate it</strong> is correct because sluggishness, drain, and flagged outbound connections to unknown servers strongly indicate a compromised device that should be isolated and cleaned.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The carrier tower is down</b>: A tower outage would not cause outbound connections to unknown servers.</span><span class='qd'><b>The user needs a louder ringtone</b>: Irrelevant to the security symptoms.</span><span class='qd'><b>The SIM needs reactivation</b>: Does not explain covert network traffic.</span>" },
{ id:"D3-108", domain:3, obj:"3.5", diff:"medium", q:"Which symptom set BEST indicates leaked or exfiltrated data from a mobile device rather than a normal performance issue?", options:["Slightly dim screen and quiet speaker","A cracked screen protector","A slow charging cable","High background network traffic, data-limit notifications, and connections to unfamiliar destinations"], answer:3, explain:"<strong>High background network traffic, data-limit notifications, and connections to unfamiliar destinations</strong> is correct because these together point to data being transmitted off the device, consistent with leakage or exfiltration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slightly dim screen and quiet speaker</b>: Cosmetic/hardware symptoms, not data leakage.</span><span class='qd'><b>A cracked screen protector</b>: Physical, not a security indicator.</span><span class='qd'><b>A slow charging cable</b>: A charging accessory issue, unrelated to data leaks.</span>" },
{ id:"D3-109", domain:3, obj:"3.5", diff:"hard", q:"A user notices the camera indicator light briefly activates while the phone is idle in their pocket, and an app they sideloaded last week has camera and microphone permissions. What is the BEST immediate action?", options:["Revoke the app's camera/microphone permissions and uninstall the suspicious sideloaded app, then scan the device","Ignore it as a glitch","Increase screen brightness","Turn off Wi-Fi calling"], answer:0, explain:"<strong>Revoke the app's camera/microphone permissions and uninstall the suspicious sideloaded app, then scan the device</strong> is correct because covert camera/mic activation tied to a sideloaded app indicates abuse, so revoking permissions, removing the app, and scanning is the right response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore it as a glitch</b>: Unexpected camera activation is a serious privacy risk.</span><span class='qd'><b>Increase screen brightness</b>: Irrelevant to the security issue.</span><span class='qd'><b>Turn off Wi-Fi calling</b>: Does not address the abusive app.</span>" },
{ id:"D3-110", domain:3, obj:"3.5", diff:"medium", q:"A user's phone repeatedly shows pop-ups and a notification that mobile data usage is unusually high; the user recently granted broad permissions to a free game. What is the BEST first step to investigate?", options:["Buy a larger data plan","Review app permissions and per-app data usage, then restrict or remove the suspicious app","Replace the screen","Disable the fingerprint reader"], answer:1, explain:"<strong>Review app permissions and per-app data usage, then restrict or remove the suspicious app</strong> is correct because checking which app consumes data and what permissions it holds identifies and addresses a likely adware or malicious app.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buy a larger data plan</b>: This hides the symptom rather than fixing the cause.</span><span class='qd'><b>Replace the screen</b>: Hardware is unrelated to data usage.</span><span class='qd'><b>Disable the fingerprint reader</b>: Has no effect on data consumption.</span>" }
);
